function Logger(prefix: string) {
  return function<T extends { new (...args: any[]): {} }>(constructor: T) {
    return class extends constructor {
      constructor(...args: any[]) {
        super(...args);
        console.log(`${prefix} - New instance created`);
      }
    };
  };
}

@Logger('INFO')
class User {
  constructor(public name: string) {}
}

const user = new User('Alice');
// Console: INFO - New instance created

function MeasureTime(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    const start = performance.now();
    const result = originalMethod.apply(this, args);
    const end = performance.now();
    console.log(`${propertyKey} took ${end - start} ms`);
    return result;
  };
}

class MathOps {
  @MeasureTime
  factorial(n: number): number {
    return n <= 1 ? 1 : n * this.factorial(n - 1);
  }
}

const math = new MathOps();
console.log(math.factorial(10));

function MinLength(limit: number) {
  return function(target: any, propertyKey: string) {
    let value: string;

    const getter = () => value;
    const setter = (val: string) => {
      if (val.length < limit) {
        throw new Error(`${propertyKey} must be at least ${limit} characters`);
      }
      value = val;
    };

    Object.defineProperty(target, propertyKey, {
      get: getter,
      set: setter,
      enumerable: true,
      configurable: true
    });
  };
}

class UserProfile {
  @MinLength(5)
  username: string;

  constructor(username: string) {
    this.username = username;
  }
}

try {
