} catch (e) {
  console.error(e.message);
}

const validProfile = new UserProfile('Joseph'); // Works fine

import 'reflect-metadata';

function Required(target: any, propertyKey: string | symbol, parameterIndex: number) {
  const existingRequiredParameters: number[] = Reflect.getOwnMetadata('requiredParameters', target, propertyKey) || [];
  existingRequiredParameters.push(parameterIndex);
  Reflect.defineMetadata('requiredParameters', existingRequiredParameters, target, propertyKey);
}

class Api {
  getData(@Required id: string) {
    console.log(`Fetching data with ID ${id}`);
  }
}

function validate(target: any, propertyName: string, descriptor: PropertyDescriptor) {
  const method = descriptor.value;
  descriptor.value = function (...args: any[]) {
    const requiredParameters: number[] = Reflect.getOwnMetadata('requiredParameters', target, propertyName);
    if (requiredParameters) {
      for (const index of requiredParameters) {
        if (args[index] == null) {
          throw new Error('Missing required argument.');
        }
      }
    }
    return method.apply(this, args);
  };
}

Reflect.decorate([validate], Api.prototype, 'getData', Object.getOwnPropertyDescriptor(Api.prototype, 'getData'));

const api = new Api();
// api.getData(null); // Throws error
api.getData('123'); // Works fine

